mapper.select:
SELECT a.id, a.goodsId, a.product_title, a.initial, a.volume, a.mchName, a.brandName, a.className, a.stockNum, a.num, a.max_num, a.starttime, a.endtime, a.is_show, a.seconds_price, a.price_type, a.`status`, a.attribute, a.goodsPrice FROM ( SELECT a.id, b.id AS goodsId, b.product_title, b.initial, b.volume, c.NAME AS mchName, d.brand_name AS brandName, e.pname AS className, a.num AS stockNum, b.num, a.max_num, a.starttime, a.endtime, a.isshow AS is_show, a.seconds_price, a.price_type, a.`status`, attr.attribute, ifnull(max(attr.price) over(partition by a.id),0) as goodsPrice, ROW_NUMBER() over(partition by a.id) AS top FROM lkt_seconds_activity a RIGHT JOIN lkt_seconds_label lab ON lab.id = a.label_id AND lab.recovery = 0 RIGHT JOIN lkt_product_list b ON a.goodsId = b.id AND b.recycle = 0 RIGHT JOIN lkt_mch c ON b.mch_id = c.id LEFT JOIN lkt_brand_class d ON b.brand_id = d.brand_id LEFT JOIN lkt_product_class e ON substring_index(substring_index(b.product_class, '-', 2), '-', -1) = e.cid LEFT JOIN lkt_configure attr ON attr.id = a.attr_id
) AS a WHERE a.top < 2
FIELD(a.`status`, 1,2,3,4,5), a.`status` ${status_sort},
limit #{pageStart},#{pageEnd}
